) VALUES
    ('CSCI-A 538', 'NETWORK TECHNOLOGIES AND SYSTEMS ADMINISTRATION', '3108', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'IF 1019', 'Jeff Whitmer', 5, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to network principles and current network technology, both hardware and software. Network administration tools and techniques. Laboratory provides practical experience.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 538', 'NETWORK TECHNOLOGIES AND SYSTEMS ADMINISTRATION', '3109', 'Class Status', 'F Friday 9:10 AM–10:00 AM', 'IF 0006', 'Staff', 5, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to network principles and current network technology, both hardware and software. Network administration tools and techniques. Laboratory provides practical experience.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 541', 'COMPUTING AND TECHNOLOGY BOOTCAMP', '36214', 'Class Status', NULL, 'HD TBA', 'Andrew (Herman) Holland', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'A high-level introduction to the many information technologies that underlie modern society for students with non-technical backgrounds. Examples include basic ideas in computing, networking, embedded systems, GPS, SCADA , algorithms and machine learning. After completion, students should be able to partake in many high-level discussions with technical leads.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 541', 'COMPUTING AND TECHNOLOGY BOOTCAMP', '8500', 'Class Status', NULL, 'WB WEB', 'Andrew (Herman) Holland', 15, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'A high-level introduction to the many information technologies that underlie modern society for students with non-technical backgrounds. Examples include basic ideas in computing, networking, embedded systems, GPS, SCADA , algorithms and machine learning. After completion, students should be able to partake in many high-level discussions with technical leads.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 581', 'INTRODUCTION TO COMPUTERS AND PROGRAMMING', '34564', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'IF 1106', 'Mitja Hmeljak', 5, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course is an introduction, broadly, to algorithmic thinking and, specifically, to programming. It teaches the basics of programming using real world applications in natural, physical and social sciences. Students will develop ability to program by identifying problems in real world and then creating a program that solves the problem.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 581', 'INTRODUCTION TO COMPUTERS AND PROGRAMMING', '34565', 'Class Status', 'F Friday 4:20 PM–6:15 PM', 'BH 118', 'Staff', 5, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course is an introduction, broadly, to algorithmic thinking and, specifically, to programming. It teaches the basics of programming using real world applications in natural, physical and social sciences. Students will develop ability to program by identifying problems in real world and then creating a program that solves the problem.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 590', 'TOPICS IN PROGRAMMING', '4181', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SB 230', 'Dan-Adrian German', 15, NULL, 'Lecture', '1.5', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Eight-week to sixteen-week course designed to provide foundations for using modern programming tools for applications and web development.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 590', 'TOPICS IN PROGRAMMING', '4182', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 308', 'Dan-Adrian German', 11, NULL, 'Lecture', '1.5', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Eight-week to sixteen-week course designed to provide foundations for using modern programming tools for applications and web development.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 590', 'TOPICS IN PROGRAMMING', '4238', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 1019', 'Jeff Whitmer', 4, NULL, 'Lecture', '1.5', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Eight-week to sixteen-week course designed to provide foundations for using modern programming tools for applications and web development.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 590', 'TOPICS IN PROGRAMMING', '4239', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 1019', 'Jeff Whitmer', 8, NULL, 'Lecture', '1.5', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Eight-week to sixteen-week course designed to provide foundations for using modern programming tools for applications and web development.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 591', 'INTRODUCTION TO COMPUTER SCIENCE', '3496', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'IF 1106', 'Carlo Angiuli', 15, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 591', 'INTRODUCTION TO COMPUTER SCIENCE', '1384', 'Class Status', 'Th Thursday 6:40 PM–8:35 PM', 'BH 118', 'Staff', 4, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 591', 'INTRODUCTION TO COMPUTER SCIENCE', '5655', 'Class Status', 'Th Thursday 1:55 PM–3:50 PM', 'BH 118', 'Staff', 1, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 591', 'INTRODUCTION TO COMPUTER SCIENCE', '6167', 'Class Status', 'F Friday 12:45 PM–2:40 PM', 'ED 2015', 'Staff', 4, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 591', 'INTRODUCTION TO COMPUTER SCIENCE', '13058', 'Class Status', 'F Friday 3:10 PM–5:05 PM', 'TV 186', 'Carlo Angiuli', 1, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 591', 'INTRODUCTION TO COMPUTER SCIENCE', '5196', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'TH A201', 'Sam Tobin-Hochstadt', 5, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 592', 'INTRODUCTION TO SOFTWARE SYSTEMS', '5656', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'MO 007', 'Joshua Crotts', 2, 'Lecture', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Design of computer software systems and introduction to programming. Topics include the C++ programming language and its data structure facilities: building and maintaining large projects: shell tools and system calls. Introduction to object-oriented programming. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 592', 'INTRODUCTION TO SOFTWARE SYSTEMS', '5657', 'Class Status', 'Th Thursday 6:40 PM–8:35 PM', 'PV 151', 'Staff', 1, 'Laboratory', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Design of computer software systems and introduction to programming. Topics include the C++ programming language and its data structure facilities: building and maintaining large projects: shell tools and system calls. Introduction to object-oriented programming. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 592', 'INTRODUCTION TO SOFTWARE SYSTEMS', '6071', 'Class Status', 'F Friday 10:25 AM–12:20 PM', 'BH 118', 'Staff', 1, 'Laboratory', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Design of computer software systems and introduction to programming. Topics include the C++ programming language and its data structure facilities: building and maintaining large projects: shell tools and system calls. Introduction to object-oriented programming. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 592', 'INTRODUCTION TO SOFTWARE SYSTEMS', '5658', 'Closed', 'Th Thursday 9:10 AM–11:05 AM', 'WY 125', 'Staff', 0, 'Laboratory', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Design of computer software systems and introduction to programming. Topics include the C++ programming language and its data structure facilities: building and maintaining large projects: shell tools and system calls. Introduction to object-oriented programming. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 592', 'INTRODUCTION TO SOFTWARE SYSTEMS', '5659', 'Closed', 'Th Thursday 4:20 PM–6:15 PM', 'BH 308', 'Staff', 0, 'Laboratory', 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Design of computer software systems and introduction to programming. Topics include the C++ programming language and its data structure facilities: building and maintaining large projects: shell tools and system calls. Introduction to object-oriented programming. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 593', 'COMPUTER STRUCTURES', '6999', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'FA 102', 'Jeremy Musser', 5, 'Lecture', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Structure and internal operation of computers. The architecture and assembly language programming of a specific computer are stressed, in addition to general principles of hardware organization and low-level software systems. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 593', 'COMPUTER STRUCTURES', '7000', 'Class Status', 'F Friday 9:10 AM–11:10 AM', 'IF 3111', 'Staff', 5, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Structure and internal operation of computers. The architecture and assembly language programming of a specific computer are stressed, in addition to general principles of hardware organization and low-level software systems. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 593', 'COMPUTER STRUCTURES', '34862', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 106', 'Jeremy Musser', 14, 'Lecture', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Structure and internal operation of computers. The architecture and assembly language programming of a specific computer are stressed, in addition to general principles of hardware organization and low-level software systems. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 593', 'COMPUTER STRUCTURES', '34863', 'Class Status', 'F Friday 8:00 AM–9:15 AM', 'IF 4111', 'Jeremy Musser', 14, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Structure and internal operation of computers. The architecture and assembly language programming of a specific computer are stressed, in addition to general principles of hardware organization and low-level software systems. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 594', 'DATA STRUCTURES', '1385', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SW 007', 'Muazzam Siddiqui', 2, 'Lecture', 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Systematic study of data structures encountered in computing problems; structure and use of storage media; methods of representing structured data; and techniques for operating on data structures. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 594', 'DATA STRUCTURES', '1386', 'Class Status', 'Th Thursday 4:30 PM–6:25 PM', 'BH 118', 'Staff', 2, 'Laboratory', 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Systematic study of data structures encountered in computing problems; structure and use of storage media; methods of representing structured data; and techniques for operating on data structures. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 595', 'FUNDAMENTALS OF COMPUTING THEORY', '9684', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 1128', 'Hamidreza Bahramian', 2, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Fundamentals of formal language theory, computation models and computability, the limits of computability and feasibility, and program verification.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 595', 'FUNDAMENTALS OF COMPUTING THEORY', '9685', 'Class Status', 'F Friday 12:45 PM–2:00 PM', 'IF 0117', 'Staff', 2, 'Discussion', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Fundamentals of formal language theory, computation models and computability, the limits of computability and feasibility, and program verification.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 596', 'PROGRAMMING LANGUAGES', '1387', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 1104', 'Chung-chieh Shan', 2, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Systematic approach to programming languages. Relationships among languages, properties and features of languages, and the computer environment necessary to use languages. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 596', 'PROGRAMMING LANGUAGES', '1388', 'Class Status', 'F Friday 10:25 AM–11:15 AM', 'BH 147', 'Staff', 2, 'Discussion', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Systematic approach to programming languages. Relationships among languages, properties and features of languages, and the computer environment necessary to use languages. Lecture and laboratory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 597', 'INTRODUCTION TO PROGRAMMING I', '1389', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 0117', 'Chenghua Tao', 4, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Fundamental programming constructs, including loops, arrays, classes, and files. General problem-solving techniques. Emphasis on modular programming, user-interface design, and developing good programming style. Not intended for computer science majors.', ARRAY[]::TEXT[], NULL),
    ('CSCI-A 597', 'INTRODUCTION TO PROGRAMMING I', '1390', 'Closed', 'Th Thursday 9:10 AM–11:05 AM', 'LI 503', 'Staff', 0, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Fundamental programming constructs, including loops, arrays, classes, and files. General problem-solving techniques. Emphasis on modular programming, user-interface design, and developing good programming style. Not intended for computer science majors.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 351', 'INTRODUCTION TO ARTIFICIAL INTELLIGENCE', '1391', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'OP 105', 'Yijie Wang', 12, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'A survey of techniques for machine intelligence and their relation to human intelligence. Topics include modeling techniques, neural networks, problem-solving methods, heuristics, search, logic, knowledge representation, machine learning, and production systems.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 355', 'AUTONOMOUS ROBOTICS', '36296', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'IF 4012', 'Lantao Liu', 3, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to the design, construction, and control of autonomous mobile robots. This course covers basic mechanics, electronics, and programming for robotics, as well as the applications of robots in cognitive science.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 363', 'BIOINFORMATICS ALGORITHMS', '7179', 'Class Status', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'GA 1100', 'Chenghua Tao', 21, 'Lecture', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The course will introduce algorithms for addressing real-world biological questions. For each topic, we will start with an important biological question and gradually present algorithms to answer this question. The course will also discuss the strategies to formulate an appropriate computation problem from a biological question to motivate algorithmic thinking.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 363', 'BIOINFORMATICS ALGORITHMS', '7180', 'Class Status', 'F Friday 9:45 AM–11:00 AM', 'LH 030', 'Staff', 13, 'Laboratory', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The course will introduce algorithms for addressing real-world biological questions. For each topic, we will start with an important biological question and gradually present algorithms to answer this question. The course will also discuss the strategies to formulate an appropriate computation problem from a biological question to motivate algorithmic thinking.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 363', 'BIOINFORMATICS ALGORITHMS', '8867', 'Class Status', 'F Friday 11:30 AM–12:45 PM', 'PV 151', 'Staff', 8, 'Laboratory', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The course will introduce algorithms for addressing real-world biological questions. For each topic, we will start with an important biological question and gradually present algorithms to answer this question. The course will also discuss the strategies to formulate an appropriate computation problem from a biological question to motivate algorithmic thinking.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 365', 'INTRODUCTION TO DATA ANALYSIS AND MINING', '7181', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LU 1001', 'Yuzhen Ye', 1, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'The course objective is to study computational aspects of discovering patterns and relationships in large data. This course is designed to introduce fundamental concepts of data mining and provide hands-on experience in data collection, preprocessing, analysis, clustering and prediction.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 392', 'COMPETITIVE PROGRAMMING', '8350', 'Class Status', 'W Wednesday 9:35 AM–10:50 AM', 'I 232', 'Christopher Raphael', 20, 'Lecture', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course focuses on training students to prepare for programming contests (such as the ACM International Collegiate Programming Contest). The students will learn to design time and space efficient algorithms to solve challenging contest problems, and produce bug-free code under the pressure of time in contest.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 392', 'COMPETITIVE PROGRAMMING', '8351', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'IF 0006', 'Staff', 20, 'Laboratory', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course focuses on training students to prepare for programming contests (such as the ACM International Collegiate Programming Contest). The students will learn to design time and space efficient algorithms to solve challenging contest problems, and produce bug-free code under the pressure of time in contest.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 401', 'FUNDAMENTALS OF COMPUTING THEORY', '5384', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 1128', 'Hamidreza Bahramian', 21, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Fundamentals of formal language theory, computation models and computability, the limits of computability and feasibility, and program verification.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 401', 'FUNDAMENTALS OF COMPUTING THEORY', '5908', 'Class Status', 'F Friday 12:45 PM–2:00 PM', 'IF 0117', 'Staff', 21, 'Discussion', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Fundamentals of formal language theory, computation models and computability, the limits of computability and feasibility, and program verification.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 403', 'INTRODUCTION TO ALGORITHM DESIGN AND ANALYSIS', '5633', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SM C141', 'Mohsen Heidari Khoozani', 4, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Algorithm design methodology. General methods for analysis of algorithms. Analysis of the performance of specific algorithms, such as those for searching and sorting.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 405', 'APPLIED ALGORITHMS', '14589', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SE 140', 'Suprovat Ghoshal', 8, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'The course will introduce basic concepts and techniques for algorithmic design and analysis. The course will emphasize key mathematical ideas in efficient algorithms. The course will develop algorithmic thinking critical for formulating computational problems for real-world applications. Prior programming experience in C/C++, Java or Python is expected.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 430', 'SECURITY FOR NETWORKED SYSTEMS', '7980', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'FA 102', 'Dongfang Zhao', 9, 'Lecture', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course is an extensive survey of network security. The course materials cover threats to information confidentiality, integrity, and availability in different internet layers, and defense mechanisms that control these threats. The course also provides a necessary foundation on network security, such as cryptographic, primitives/protocols, authentication, authorization and access control technologies; and hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 430', 'SECURITY FOR NETWORKED SYSTEMS', '7981', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'IF 3115', 'Staff', 2, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course is an extensive survey of network security. The course materials cover threats to information confidentiality, integrity, and availability in different internet layers, and defense mechanisms that control these threats. The course also provides a necessary foundation on network security, such as cryptographic, primitives/protocols, authentication, authorization and access control technologies; and hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 430', 'SECURITY FOR NETWORKED SYSTEMS', '35042', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'IF 3115', 'Dongfang Zhao', 8, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course is an extensive survey of network security. The course materials cover threats to information confidentiality, integrity, and availability in different internet layers, and defense mechanisms that control these threats. The course also provides a necessary foundation on network security, such as cryptographic, primitives/protocols, authentication, authorization and access control technologies; and hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 430', 'SECURITY FOR NETWORKED SYSTEMS', '8094', 'Closed', 'Th Thursday 11:10 AM–12:25 PM', 'IF 3115', 'Staff', 0, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course is an extensive survey of network security. The course materials cover threats to information confidentiality, integrity, and availability in different internet layers, and defense mechanisms that control these threats. The course also provides a necessary foundation on network security, such as cryptographic, primitives/protocols, authentication, authorization and access control technologies; and hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 430', 'SECURITY FOR NETWORKED SYSTEMS', '11897', 'Closed', 'Th Thursday 12:45 PM–2:00 PM', 'IF 3115', 'Dongfang Zhao', 0, 'Laboratory', 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course is an extensive survey of network security. The course materials cover threats to information confidentiality, integrity, and availability in different internet layers, and defense mechanisms that control these threats. The course also provides a necessary foundation on network security, such as cryptographic, primitives/protocols, authentication, authorization and access control technologies; and hands-on experiences through programming assignments and course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 455', 'PRINCIPLES OF MACHINE LEARNING', '13499', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1118', 'Jiangpeng He', 21, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'In this course, we explore (machine learning) algorithms that can learn from and make predictions on data. This course introduces the statistical, mathematical, and computational foundations of these frameworks, with a strong focus on understanding the mathematical derivations for the algorithms and simultaneously implementing the algorithms.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 461', 'DATABASE CONCEPTS', '1392', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'LU 1001', 'Da Yan', 14, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Introduction to database concepts and systems. Topics include database models and systems; hierarchal, network, relational, and object-oriented; database design principles; structures for efficient data access; query languages and processing; database applications development; views; security; concurrency; recovery. Students participate in a project to design, implement, and query a database using a standard database system.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 481', 'INTERACTIVE GRAPHICS', '10492', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'IF 4063', 'Mitja Hmeljak', 3, 'Lecture', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'Computer graphics techniques. Introduction to graphics hardware and software. Two-dimensional graphics methods, transformations, and interactive methods. Three-dimensional graphics, transformations, viewing geometry, object modeling, and interactive manipulation methods. Basic lighting and shading. Video and animation methods.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 481', 'INTERACTIVE GRAPHICS', '10493', 'Class Status', 'F Friday 3:55 PM–5:10 PM', 'IF 0119', 'Staff', 3, 'Laboratory', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'Computer graphics techniques. Introduction to graphics hardware and software. Two-dimensional graphics methods, transformations, and interactive methods. Three-dimensional graphics, transformations, viewing geometry, object modeling, and interactive manipulation methods. Basic lighting and shading. Video and animation methods.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 490', 'SEMINAR IN COMPUTER SCIENCE', '14630', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 1106', 'Kurt Seiffert', 3, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Special topics in computer science.', ARRAY[]::TEXT[], NULL),
