    ('CSCI-B 490', 'SEMINAR IN COMPUTER SCIENCE', '33816', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1134', 'Thai Le', 6, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Special topics in computer science.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 490', 'SEMINAR IN COMPUTER SCIENCE', '35857', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LI 026', 'Byung-Cheol Min', 5, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Special topics in computer science.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 501', 'THEORY OF COMPUTING', '5660', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 4012', 'Erik Wennstrom', 5, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Deterministic and nondeterministic automata, regular expressions, pumping lemmas; context-free languages, parsing, pushdown automata, context-sensitive languages, LBA, LR(k) languages, closure and decidability of language classes. Turing machines, random access machines, grammars, general recursive functions, equivalence of computation models, universal machines, relative computing. Unsolvability, semi-recursive sets, Rice''s Theorem. Space and time complexity. NP completeness.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 501', 'THEORY OF COMPUTING', '5661', 'Class Status', 'F Friday 12:45 PM–2:00 PM', 'IF 4012', 'Staff', 5, 'Discussion', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Deterministic and nondeterministic automata, regular expressions, pumping lemmas; context-free languages, parsing, pushdown automata, context-sensitive languages, LBA, LR(k) languages, closure and decidability of language classes. Turing machines, random access machines, grammars, general recursive functions, equivalence of computation models, universal machines, relative computing. Unsolvability, semi-recursive sets, Rice''s Theorem. Space and time complexity. NP completeness.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 503', 'ALGORITHMS DESIGN AND ANALYSIS', '10073', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'I 107', 'Qin Zhang', 15, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Models, algorithms, recurrences, summations, growth rates. Probabilistic tools, upper and lower bounds; worst-case and average-case analysis, amortized analysis, dynamization. Comparison-based algorithms: search, selection, sorting, hashing. Information extraction algorithms (graphs, databases). Graphs algorithms: spanning trees, shortest paths, connectivity, depth-first search, breadth-first search.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 505', 'APPLIED ALGORITHMS', '7710', 'Class Status', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'IF 1106', 'Sakher Qaaidi', 132, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course studies the design, implementation, and analysis of algorithms and data structures as applied to real world problems. The topics include divide-and-conquer, optimization, and randomized algorithms applied to problems such as sorting, searching, and graph analysis. The course teaches trees, hash tables, heaps, and graphs.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 505', 'APPLIED ALGORITHMS', '7711', 'Class Status', 'F Friday 10:20 AM–11:10 AM', 'I 109', 'Staff', 21, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course studies the design, implementation, and analysis of algorithms and data structures as applied to real world problems. The topics include divide-and-conquer, optimization, and randomized algorithms applied to problems such as sorting, searching, and graph analysis. The course teaches trees, hash tables, heaps, and graphs.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 505', 'APPLIED ALGORITHMS', '10744', 'Class Status', 'F Friday 12:40 PM–1:30 PM', 'IF 1019', 'Staff', 29, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course studies the design, implementation, and analysis of algorithms and data structures as applied to real world problems. The topics include divide-and-conquer, optimization, and randomized algorithms applied to problems such as sorting, searching, and graph analysis. The course teaches trees, hash tables, heaps, and graphs.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 505', 'APPLIED ALGORITHMS', '11087', 'Class Status', 'F Friday 11:30 AM–12:20 PM', 'BH 308', 'Staff', 22, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course studies the design, implementation, and analysis of algorithms and data structures as applied to real world problems. The topics include divide-and-conquer, optimization, and randomized algorithms applied to problems such as sorting, searching, and graph analysis. The course teaches trees, hash tables, heaps, and graphs.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 505', 'APPLIED ALGORITHMS', '7911', 'Class Status', NULL, 'OL ONLINE', 'Sakher Qaaidi', 19, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'The course studies the design, implementation, and analysis of algorithms and data structures as applied to real world problems. The topics include divide-and-conquer, optimization, and randomized algorithms applied to problems such as sorting, searching, and graph analysis. The course teaches trees, hash tables, heaps, and graphs.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 521', 'PROGRAMMING LANGUAGE PRINCIPLES', '1393', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'I 109', 'Amr Sabry', 5, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Systematic approach to programming languages. Relationships among languages, properties and features of languages, the computer environment necessary to support language execution.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 544', 'SECURITY FOR NETWORKED SYSTEMS', '9454', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WY 005', 'Yan Huang', 46, 'Lecture', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 544', 'SECURITY FOR NETWORKED SYSTEMS', '10061', 'Class Status', 'F Friday 11:30 AM–12:20 PM', 'IF 3115', 'Yan Huang', 16, 'Laboratory', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 544', 'SECURITY FOR NETWORKED SYSTEMS', '10754', 'Class Status', 'F Friday 12:40 PM–1:30 PM', 'IF 3115', 'Yan Huang', 5, 'Laboratory', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 544', 'SECURITY FOR NETWORKED SYSTEMS', '13506', 'Class Status', 'F Friday 1:50 PM–2:40 PM', 'IF 3115', 'Yan Huang', 25, 'Laboratory', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 544', 'SECURITY FOR NETWORKED SYSTEMS', '7912', 'Class Status', NULL, 'OL ONLINE', 'Yan Huang', 6, 'Lecture', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 551', 'ELEMENTS OF ARTIFICIAL INTELLIGENCE', '6904', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'IF 1106', 'David Leake', 123, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to major issues and approaches in artificial intelligence. Principles of reactive, goal-based, and utility-based agents. Problem-solving and search. Knowledge representation and design of representational vocabularies. Inference and theorem proving, reasoning under uncertainty, planning. Overview of machine learning.', ARRAY['Class uses IU eTexts'], NULL),
    ('CSCI-B 551', 'ELEMENTS OF ARTIFICIAL INTELLIGENCE', '7910', 'Class Status', NULL, 'OL ONLINE', 'Saul Blanco Rodriguez', 74, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to major issues and approaches in artificial intelligence. Principles of reactive, goal-based, and utility-based agents. Problem-solving and search. Knowledge representation and design of representational vocabularies. Inference and theorem proving, reasoning under uncertainty, planning. Overview of machine learning.', ARRAY['Class uses IU eTexts'], NULL),
    ('CSCI-B 557', 'MUSIC INFORMATION PROCESSING: AUDIO', '14703', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'I 321A', 'Christopher Raphael', 17, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course discusses music analysis and processing problems that use sampled audio as the primary data representation. Digital signal processing is discussed, along with filtering and its relationship to Fourier techniques. Applications considered include score following, automatic music transcription and annotation from audio, musical accompaniment systems, and audio effects.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 561', 'ADVANCED DATABASE CONCEPTS', '10869', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'ED 1120', 'Chenghong Wang', 121, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Database models and systems: especially relational and object-oriented; relational database design theory; structures for efficient data access; query languages and processing; database applications development; views. Transaction management: concurrency and recovery.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 565', 'DATA MINING', '6731', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'MO 007', 'Dongruo Zhou', 199, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Algorithmic and practical aspects of discovering patterns and relationships in large databases. The course also provides hands-on experience in data analysis, clustering and prediction. Topics include: data preprocessing and exploration, data warehousing, association rule mining, classification and regression, clustering, anomaly detection, human factors and social issues in data mining.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 581', 'ADVANCED COMPUTER GRAPHICS', '10494', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'IF 4063', 'Mitja Hmeljak', 13, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to graphics hardware and software. Two-dimensional graphics methods, transformations, and interactive methods. Three-dimensional graphics, transformations, viewing geometry, object modeling and interactive manipulation methods. Basic lighting and shading. Video and animation methods.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 581', 'ADVANCED COMPUTER GRAPHICS', '10495', 'Class Status', 'F Friday 3:55 PM–5:10 PM', 'IF 0119', 'Staff', 13, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to graphics hardware and software. Two-dimensional graphics methods, transformations, and interactive methods. Three-dimensional graphics, transformations, viewing geometry, object modeling and interactive manipulation methods. Basic lighting and shading. Video and animation methods.', ARRAY[]::TEXT[], NULL),
