    ('CSCI-B 590', 'TOPICS IN COMPUTER SCIENCE', '11562', 'Closed', 'W Wednesday 3:55 PM–6:55 PM', 'IF 3111', 'Andrew Lukefahr', 0, 'Lecture', 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Special topics in computer science.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 599', 'TEACHING IN COMPUTER SCIENCE', '9271', 'Class Status', 'W Wednesday 9:35 AM–10:50 AM', 'IF 0006', 'Michele Roberts', 18, NULL, 'Lecture', '1', 'LUDDY HALL', ARRAY[]::TEXT[], 'General principles of teaching and practical experiences that relate to teaching computer science. An important feature of the course is the micro-teaching, in which each participant prepares and delivers short lectures to the seminar participants. Each presentation is followed by critical analysis and discussion.', ARRAY[]::TEXT[], NULL),
    ('CSCI-B 649', 'TOPICS IN SYSTEMS', '8705', 'Class Status', 'Tu Tuesday 12:45 PM–3:15 PM', 'IF 3115', 'Fares Alharbi, Jiale Guan', 12, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Special topics in systems.', ARRAY[]::TEXT[], NULL),
