    ('CSCI-C 102', 'GREAT IDEAS IN COMPUTING', '8072', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:40 PM', 'SY 003', 'Charles Pope', 1, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Survey of great ideas in computing and the role of computing in the modern world. Explores how people use computing tools to realize their ideas. Emphasis on the impact of modern technology and the use of hardware and software to create solutions to everyday problems. Lecture and laboratory.', ARRAY['IUB GenEd N&M credit'], NULL),
    ('CSCI-C 200', 'INTRODUCTION TO COMPUTERS AND PROGRAMMING', '7439', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'FA 015', 'Mehmet Dalkilic', 55, 'Lecture', 'Lecture', '4', 'FINE ARTS', ARRAY[]::TEXT[], 'This course is an introduction, broadly, to algorithmic thinking and, specifically, to programming. It teaches the basics of programming using real world applications in natural, physical and social sciences. Students will develop ability to program by identifying problems in real world and then creating a program that solves the problem.', ARRAY['IUB GenEd N&M credit'], NULL),
