    ('CSCI-C 211', 'INTRODUCTION TO COMPUTER SCIENCE', '5197', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'TH A201', 'Sam Tobin-Hochstadt', 46, 'Lecture', 'Lecture', '4', 'LEE NORVELLE THEATRE DRAMA/ NE', ARRAY[]::TEXT[], 'A first course in computer science for those intending to take advanced computer science courses. Introduction to programming and to algorithm design and analysis. Using the Scheme programming language, the course covers several programming paradigms. Lecture and laboratory.', ARRAY['IUB GenEd N&M credit'], NULL),
