    ('CSCI-C 231', 'INTRODUCTION TO THE MATHEMATICS OF CYBERSECURITY', '8603', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GY 1050', 'Hamidreza Bahramian', 0, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'The goal of this course is for students to be introduced to the basic mathematical tools used in modern cybersecurity. The course covers introductory mathematical material from a number of disparate fields including probability theory, analysis of algorithms, complexity theory, number theory, and group theory.', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 241', 'DISCRETE STRUCTURES FOR COMPUTER SCIENCE', '1395', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'IF 1106', 'Erik Wennstrom, Nicholas LaRacuente', 3, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Induction and recursive programs, running time, asymptotic notations, combinatorics and discrete probability, trees and lists, the relational data model, graph algorithms, propositional and predicate logic.', ARRAY[]::TEXT[], NULL),
