    ('CSCI-C 291', 'SYSTEM PROGRAMMING WITH C AND UNIX', '9103', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'IF 1104', 'Olgun Sadik', 1, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course provides an introduction to programming in a Unix (Linux) environment using the C language. The key ideas to be discussed are: the Unix shell, file system and basic shell commands; the emacs text editor; and the C programming language.', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 291', 'SYSTEM PROGRAMMING WITH C AND UNIX', '10072', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AC C002', 'Abhishek Bisht', 16, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course provides an introduction to programming in a Unix (Linux) environment using the C language. The key ideas to be discussed are: the Unix shell, file system and basic shell commands; the emacs text editor; and the C programming language.', ARRAY[]::TEXT[], NULL),
