    ('CSCI-C 292', 'INTRODUCTION TO GAME PROGRAMMING', '9078', 'Class Status', 'M Monday 3:55 PM–5:10 PM', 'IF 1106', 'Andrew (Herman) Holland', 31, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course explores the world of game development with a focus on programming for games. It provides an introduction to game programming using a state-of-the-art language (e.g., C#) in a game engine (e.g., Unity).', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 292', 'INTRODUCTION TO GAME PROGRAMMING', '9347', 'Class Status', 'TuTh Tuesday, Thursday 7:05 PM–8:25 PM', 'BH 107', 'Andrew (Herman) Holland', 1, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course explores the world of game development with a focus on programming for games. It provides an introduction to game programming using a state-of-the-art language (e.g., C#) in a game engine (e.g., Unity).', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 292', 'INTRODUCTION TO GAME PROGRAMMING', '9079', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:50 PM', 'BH 118', 'Andrew (Herman) Holland', 0, 'Laboratory', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course explores the world of game development with a focus on programming for games. It provides an introduction to game programming using a state-of-the-art language (e.g., C#) in a game engine (e.g., Unity).', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 295', 'LEADERSHIP AND LEARNING', '9270', 'Class Status', 'W Wednesday 9:35 AM–10:50 AM', 'IF 0006', 'Michele Roberts', 18, NULL, 'Lecture', '1', 'LUDDY HALL', ARRAY[]::TEXT[], 'Students in this course learn and practice how to teach fundamental Computer Science concepts and skills, and investigate strategies to increase K-12 students'' interest in CS with different race, gender, age, socioeconomic status, and academic background. Furthermore, this course trains undergraduate instructors in the department to better perform their duties.', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 311', 'PROGRAMMING LANGUAGES', '1397', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 1104', 'Chung-chieh Shan', 10, 'Lecture', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'Systematic approach to programming languages. Relationships among languages, properties, and features of languages; and the computer environment necessary to use languages.', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 311', 'PROGRAMMING LANGUAGES', '1398', 'Class Status', 'F Friday 10:25 AM–11:15 AM', 'BH 147', 'Staff', 1, 'Discussion', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'Systematic approach to programming languages. Relationships among languages, properties, and features of languages; and the computer environment necessary to use languages.', ARRAY[]::TEXT[], NULL),
