    ('CSCI-C 322', 'OBJECT-ORIENTED SOFTWARE METHODS', '11448', 'Closed', 'Th Thursday 6:30 PM–7:45 PM', 'WY 125', 'Dan-Adrian German', 0, 'Laboratory', 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Design and implementation of complex software systems and applications exploiting the object-oriented paradigm. Selection and effective utilization of object-oriented libraries and interfaces.', ARRAY[]::TEXT[], NULL),
    ('CSCI-C 323', 'MOBILE APP DEVELOPMENT', '8349', 'Class Status', 'M Monday 12:45 PM–2:00 PM', 'IF 0117', 'Sakher Qaaidi', 1, 'Lecture', 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course focuses on development of mobile applications for modern platforms and introduces common tools and languages used. The course will emphasize the app development cycle: application design, development, testing, publishing and distribution; development tools and emulators/simulators; user interface layout; using sensors including touch, geo-location and orientation; and data management.', ARRAY[]::TEXT[], NULL),
