    ('CSCI-C 460', 'SENIOR PROJECT I', '9450', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FF 073', 'William Emigh', 0, NULL, 'Activity', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Students work on projects in supervised teams, from planning and design to implementation, testing and releasing of a final product. Teamwork, communication, and organizational skills are emphasized in a real-world-style environment.', ARRAY[]::TEXT[], NULL),
    ('CSCI-G 901', 'ADVANCED RESEARCH', '1403', 'Class Status', NULL, NULL, 'Roni Khardon', 25, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
