    ('CSCI-P 423', 'COMPILERS', '7505', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I 107', 'Jeremy Siek', 0, NULL, 'Lecture', '4', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Compiler design and construction, including lexical analysis, parsing, code generation, and optimization. Extensive laboratory exercises.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 438', 'INTRODUCTION TO COMPUTER NETWORKS', '4370', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 1106', 'Jeremy Musser', 0, 'Lecture', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'Foundations of computer networks. Networking hardware technology such as Ethernet, ATM, wireless. Networking protocols (TCP/IP) routing, error correcting. Network services such as DNS, Web servers, virtual private networks (VPN), open SSL.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 438', 'INTRODUCTION TO COMPUTER NETWORKS', '6171', 'Closed', 'F Friday 1:55 PM–2:45 PM', 'IF 1104', 'Staff', 0, 'Discussion', 'Lecture', '4', 'LUDDY HALL', ARRAY[]::TEXT[], 'Foundations of computer networks. Networking hardware technology such as Ethernet, ATM, wireless. Networking protocols (TCP/IP) routing, error correcting. Network services such as DNS, Web servers, virtual private networks (VPN), open SSL.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 465', 'SOFTWARE ENGINEERING FOR INFORMATION SYSTEMS I', '7709', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 1106', 'Kurt Seiffert', 7, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Analysis design, and implementation of information systems. Project specification. Data modeling. Software design methodologies. Software quality assurance. Supervised team development of a real system for a real client.', ARRAY[]::TEXT[], NULL),
