    ('CSCI-P 523', 'PROGRAMMING LANGUAGE IMPLEMENT', '7506', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I 107', 'Jeremy Siek', 3, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Implementation of traditional and nontraditional computer programming languages. Compilation, including lexical analysis, parsing, optimization, code generation, and testing. Run-time support, including run-time libraries, storage management, input-output. Comparison of implementation techniques. Extensive laboratory exercises.', ARRAY[]::TEXT[], NULL),
