    ('CSCI-P 556', 'APPLIED MACHINE LEARNING', '7721', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 100', 'Zoran Tiganj', 157, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The main aim of the course is to provide skills to apply machine learning algorithms on real applications. We will consider fewer learning algorithms and less time on math and theory and instead spend more time on hands-on skills required for algorithms to work on a variety of data sets.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 556', 'APPLIED MACHINE LEARNING', '36806', 'Class Status', NULL, 'WB WEB', 'Yongsheng Bai', 27, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The main aim of the course is to provide skills to apply machine learning algorithms on real applications. We will consider fewer learning algorithms and less time on math and theory and instead spend more time on hands-on skills required for algorithms to work on a variety of data sets.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 556', 'APPLIED MACHINE LEARNING', '36807', 'Class Status', NULL, 'WB WEB', 'Yongsheng Bai', 11, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The main aim of the course is to provide skills to apply machine learning algorithms on real applications. We will consider fewer learning algorithms and less time on math and theory and instead spend more time on hands-on skills required for algorithms to work on a variety of data sets.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 565', 'SOFTWARE ENGINEERING I', '7716', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'IF 1106', 'Kurt Seiffert', 9, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Analysis, design and implementation of software systems. Requirements specification: data and process modeling. Software design methodologies. Software quality assurance: testing and verification. Software development processes.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 565', 'SOFTWARE ENGINEERING I', '11598', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 003', 'Kurt Seiffert', 31, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Analysis, design and implementation of software systems. Requirements specification: data and process modeling. Software design methodologies. Software quality assurance: testing and verification. Software development processes.', ARRAY[]::TEXT[], NULL),
    ('CSCI-P 566', 'SOFTWARE ENGINEERING II', '15284', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LU 1001', 'Hamidreza Bahramian', 46, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Analysis, design and implementation of software systems. Requirements specification: data and process modeling. Software design methodologies. Software quality assurance: testing and verification. Software development processes.', ARRAY[]::TEXT[], NULL),
    ('CSCI-T 500', 'COMPUTER SCIENCE FOUNDATIONS', '15299', 'Class Status', NULL, 'OL ONLINE', 'Michele Roberts', 17, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This is a graduate level course designed to introduce foundational Computer Science concepts to students who did not complete undergraduate Computer Science coursework. Created primarily for K-12 educational stakeholders, the course is also appropriate for college graduate audiences of non-computing disciplines interested in beginning a broad exploration of the field.', ARRAY[]::TEXT[], NULL),
    ('CSCI-T 510', 'INTRODUCTION TO COMPUTERS AND PROGRAMMING', '15300', 'Class Status', NULL, 'OL ONLINE', 'Michele Roberts', 18, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This is a graduate level course designed to introduce programming to students who did not complete undergraduate Computer Science coursework. Created for K-12 educational stakeholders, the course is also appropriate for college graduate audiences of non-computing disciplines interested in beginning exploration of programming.', ARRAY[]::TEXT[], NULL),
    ('CSCI-T 520', 'INTRODUCTION TO SOFTWARE SYSTEMS', '34793', 'Class Status', NULL, 'OL ONLINE', 'Suranga Hettiarachchi', 12, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This graduate level course is designed as a second semester programming course for students who did not complete undergraduate Computer Science coursework. Created primarily for K-12 teachers, administrators and other educational stakeholders, it''s also appropriate for college graduate audiences of non-computing disciplines interested in programming skills and understanding software systems.', ARRAY['Class uses IU eTexts'], NULL),
