    ('CSCI-Y 395', 'CAREER DEVELOPMENT FOR CSCI MAJORS', '7604', 'Class Status', 'Tu Tuesday 11:10 AM–12:25 PM', 'AC C114', 'David Gregoire', 7, NULL, 'Lecture', '1', 'CEDAR HALL', ARRAY[]::TEXT[], 'Develop skills and knowledge that enable you to successfully pursue your career search, both at the time of graduation and later as you progress through your career. The course covers techniques and strategies which make your job search more efficient and effective.', ARRAY[]::TEXT[], NULL),
