    ('CSCI-Y 799', 'COMPUTER SCIENCE COLLOQUIUM', '9094', 'Class Status', 'F Friday 2:30 PM–4:15 PM', 'IF 1106', 'Dongruo Zhou, Nicholas LaRacuente', 21, NULL, 'Seminar', '1', 'LUDDY HALL', ARRAY[]::TEXT[], 'A series of talks by researchers in computer science and closely related areas presenting their recent research. A minimum of 75% attendance and course work in the form of a written report based on the talk by any colloquium speaker are required for credit.', ARRAY[]::TEXT[], NULL),
