    ('CTIH-T 500', 'INTRODUCTION TO THE THEORETICAL FOUNDATIONS OF THE HUMANITIES', '32300', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'ED 3004', 'Patrick Dove', 1, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduces major questions and ideas in the study of the theoretical foundations of the humanities.', ARRAY[]::TEXT[], NULL),
    ('CTIH-T 600', 'TOPICS IN CRITICAL THEORY', '13233', 'Class Status', 'W Wednesday 3:55 PM–6:25 PM', 'BH 142', 'Eyal Peretz', 13, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In-depth study of a concept, period, or problem in the study of the theoretical foundations of the humanities. Topics may vary.', ARRAY[]::TEXT[], NULL),
    ('CTIH-T 600', 'TOPICS IN CRITICAL THEORY', '29715', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 306', 'Drew Dalton', 8, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In-depth study of a concept, period, or problem in the study of the theoretical foundations of the humanities. Topics may vary.', ARRAY[]::TEXT[], NULL),
    ('CTIH-T 700', 'INDEPENDENT STUDY IN CRITICAL THEORY', '6604', 'Class Status', NULL, NULL, 'Michel Chaouli', 14, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Independent Study', ARRAY[]::TEXT[], NULL),
    ('CULS-C 601', 'INTRODUCTION TO CULTURAL STUDIES', '34465', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'LH 112', 'Rebekah Sheldon', 2, NULL, 'Lecture', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Survey of main issues, theories, and methods in cultural studies. Topics may include communications and mass culture; gender, race, and the social construction of identity; historiographic and ethnographic approaches to modern cultures and societies.', ARRAY[]::TEXT[], NULL),
    ('CULS-C 701', 'SPECIAL TOPICS IN CULTURAL STUDIES', '34125', 'Class Status', 'Th Thursday 5:30 PM–7:45 PM', 'BH 015', 'Teresa Kovacs', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced exploration of a specific issue in cultural studies (for example, "Avant garde" movements in politics and the arts in relation to social and cultural modernity).', ARRAY[]::TEXT[], NULL),
    ('CULS-C 701', 'SPECIAL TOPICS IN CULTURAL STUDIES', '34229', 'Class Status', 'W Wednesday 11:10 AM–2:10 PM', 'BH 338', 'A. Freya Thimsen', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced exploration of a specific issue in cultural studies (for example, "Avant garde" movements in politics and the arts in relation to social and cultural modernity).', ARRAY[]::TEXT[], NULL),
    ('CULS-C 701', 'SPECIAL TOPICS IN CULTURAL STUDIES', '34466', 'Class Status', 'W Wednesday 10:25 AM–1:25 PM', 'BH 123', 'Hannah Airriess', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced exploration of a specific issue in cultural studies (for example, "Avant garde" movements in politics and the arts in relation to social and cultural modernity).', ARRAY[]::TEXT[], NULL),
    ('CULS-C 701', 'SPECIAL TOPICS IN CULTURAL STUDIES', '34467', 'Class Status', 'Th Thursday 12:45 PM–3:15 PM', 'FF 212', 'Rachel Plotnick', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced exploration of a specific issue in cultural studies (for example, "Avant garde" movements in politics and the arts in relation to social and cultural modernity).', ARRAY[]::TEXT[], NULL),
    ('CULS-C 701', 'SPECIAL TOPICS IN CULTURAL STUDIES', '34468', 'Class Status', 'W Wednesday 4:00 PM–6:30 PM', 'BH 315', 'Vincent Bouchard', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced exploration of a specific issue in cultural studies (for example, "Avant garde" movements in politics and the arts in relation to social and cultural modernity).', ARRAY[]::TEXT[], NULL),
    ('CULS-C 790', 'INDEPENDENT READINGS IN CULTURAL STUDIES', '5904', 'Class Status', NULL, NULL, 'Ishan Ashutosh', 2, NULL, 'Independent Study', '4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('DAH-R 700', 'DIGITAL ARTS & HUMANITIES CAPSTONE', '36760', 'Class Status', NULL, NULL, 'Elizabeth Dunn', 24, NULL, 'Independent Study', '1–5', NULL, ARRAY[]::TEXT[], 'The Digital Arts & Humanities Capstone is a 1-5 credit independent study focused on the digital component of a thesis project. Students prepare components of a digital project, which can include a project proposal/charter, an environmental scan and sustainability plan, a prototype, and a critical reflection on the finished submission.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 321', 'DATA REPRESENTATION', '29812', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LU 1001', 'Muazzam Siddiqui', 29, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'This course covers a wide variety of data representations and data processes that are core parts of the data/information ecosystem. The focus is on essential aspects and mechanisms of data engineering to prepare data for data science and machine learning problems and applications.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 351', 'BIG DATA ANALYTICS', '11155', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'BH 104', 'Haixu Tang', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course introduces the fundamentals of data science and big data analysis by focusing on: theoretical aspects, such as their philosophical grounds and implications, and methodological aspects, such as large-scale data processing, statistical analysis and machine learning, data retrieval and recommendation, data representation and semantics, along with several case studies.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 390', 'UNDERGRADUATE INDEPENDENT STUDY', '13155', 'Class Status', NULL, NULL, 'Mehmet Dalkilic', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a department technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 390', 'UNDERGRADUATE INDEPENDENT STUDY', '10999', 'Class Status', NULL, NULL, 'Paul Macklin, Tiana Iruoje', 14, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a department technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 390', 'UNDERGRADUATE INDEPENDENT STUDY', '13138', 'Class Status', NULL, NULL, 'Mehmet Dalkilic', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent research based on existing literature or original work. A report, in the style of a department technical report, is required.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 498', 'DATA SCIENCE CAPSTONE I', '11672', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'AC C112', 'Muazzam Siddiqui', 7, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This first course of two introduces students to a real-world, group project that includes statement of work, requirements gathering, data science system design and implementation, product delivery, and assessment of work. The first course is devoted to identifying team projects, understanding the customers'' needs and preliminary tasks for the project.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 532', 'APPLIED DATABASE TECHNOLOGIES', '12751', 'Class Status', NULL, 'WB WEB', 'Olga Scrivner', 6, 'Lecture', 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course aims to provide the basic overview of the current database landscape, starting with relational databases, SQL, and moving to several different NoSQL databases, such as XML database, MongoDB, Neo4j, Cassandra, and HBase.', ARRAY['Class uses IU eTexts'], NULL),
