    ('DSCI-D 592', 'DATA SCIENCE IN PRACTICE', '36387', 'Class Status', NULL, 'WB WEB', 'David Wild', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Students are organized into teams to carry out real world projects in conjunction with project sponsors, while learning about methodologies for data science consulting.', ARRAY[]::TEXT[], NULL),
    ('DSCI-D 595', 'DATA SCIENCE ON-RAMP', '35756', 'Class Status', NULL, 'WB WEB', 'Nasim Anousheh', 20, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The Data Science On-Ramp contains a series of self-paced modules to build and enhance your data science skill set, oftentimes demanded or desired in data science related jobs. Each module is equal to one (1) credit hour. As such, the Data Science On-Ramp course has variable credit hours.', ARRAY[]::TEXT[], NULL),
