    ('EALC-C 103', 'ADVANCED ELEMENTARY CHINESE I', '12957', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 1:55 PM–2:45 PM', 'I 105', 'Yingling Bao', 8, NULL, 'Lecture', '4', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'For students with significant speaking and listening abilities, through home exposure or prior overseas experience. Emphasis on developing students'' ability to read and write Chinese with commonly used characters, though pronunciation and speaking are also stressed.', ARRAY['IUB GenEd World Language class'], NULL),
    ('EALC-C 201', '2ND YEAR CHINESE 1', '4727', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'AC C112', 'Xiaoying Liles', 10, 'Lecture', 'Lecture', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'Explores the broader cultural context in which language is used, including more subtle oral and written forms. Investigates multiple perspectives in addition to the speaker''s.', ARRAY['IUB GenEd World Language class'], NULL),
