    ('EALC-C 301', 'THIRD YEAR CHINESE 1', '5670', 'Closed', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 016', 'Yuan Lu', 0, 'Drill', 'Lecture', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Emphasis on practice in understanding the difference between oral and written expression, building up discourse-level narration skills, and developing reading strategies for coping with authentic texts.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 301', 'THIRD YEAR CHINESE 1', '8852', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'SE 010', 'Yuan Lu', 3, 'Lecture', 'Lecture', '4', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Emphasis on practice in understanding the difference between oral and written expression, building up discourse-level narration skills, and developing reading strategies for coping with authentic texts.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 306', 'LITERARY CHINESE I', '14713', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 331', 'Manling Luo', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An introduction to wenyanwen, the written language of traditional Chinese literary and documentary forms, through the study of selected texts of different genres and periods. Texts may range from ancient writings to modern prose influence by traditional style. This course does not satisfy the College of Arts and Sciences language requirement.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 401', 'FOURTH YEAR CHINESE I', '1429', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SY 037', 'Xiaoying Liles', 6, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Emphasis on understanding and appreciating Chinese literary genres and prose.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 401', 'FOURTH YEAR CHINESE I', '11373', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 238', 'Ya Wen Tsai', 6, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Emphasis on understanding and appreciating Chinese literary genres and prose.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 408', 'CHINESE LANGUAGE PRACTICE I', '9254', 'Class Status', 'W Wednesday 3:10 PM–4:00 PM', 'I 105', 'Yingling Bao', 6, NULL, 'Practice', '1', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'For students who want simultaneously to improve their content knowledge and language skills through reading, writing practice, and discussion of various topics in Chinese.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 457', 'CHINESE IN HUMANITIES', '7958', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 338', 'Yea-Fen Chen', 2, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced language practice associated with authentic academic texts in humanities discipline. Emphasis on interpreting, analyzing, and presenting Chinese cultural concepts, artifacts, and events from a global perspective, for an authentic purpose, and within a performance assessment framework. May be offered independently in Chinese, or linked with an English-language content course.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 457', 'CHINESE IN HUMANITIES', '11421', 'Class Status', NULL, NULL, 'Yea-Fen Chen', 2, 'Drill', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced language practice associated with authentic academic texts in humanities discipline. Emphasis on interpreting, analyzing, and presenting Chinese cultural concepts, artifacts, and events from a global perspective, for an authentic purpose, and within a performance assessment framework. May be offered independently in Chinese, or linked with an English-language content course.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 467', 'CHINESE IN SOCIAL SCIENCE', '9092', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 240', 'Yingling Bao', 0, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced language practice associated with authentic academic texts in social science disciplines. Emphasis on interpreting, analyzing, and presenting Chinese cultural concepts, practice, and events from a global perspective, for an authentic purpose, and within a performance assessment framework. May be offered independently in Chinese, or linked with an English-language content course.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 467', 'CHINESE IN SOCIAL SCIENCE', '9483', 'Closed', NULL, NULL, 'Yingling Bao', 0, 'Drill', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced language practice associated with authentic academic texts in social science disciplines. Emphasis on interpreting, analyzing, and presenting Chinese cultural concepts, practice, and events from a global perspective, for an authentic purpose, and within a performance assessment framework. May be offered independently in Chinese, or linked with an English-language content course.', ARRAY[]::TEXT[], NULL),
    ('EALC-C 505', 'TOPICS IN CHINESE STUDIES', '29640', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 270', 'Yuan Lu', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Graduate colloquium on aspects of Chinese literature, thought, or society. Topics will vary. A substantial portion of coursework and readings will be in Chinese.', ARRAY[]::TEXT[], NULL),
