    ('EALC-C 527', 'PRACTICUM IN CHINESE LANGUAGE PEDAGOGY', '3285', 'Class Status', NULL, NULL, 'Yuan Lu', 10, NULL, 'Practicum', '2–3', NULL, ARRAY[]::TEXT[], 'Supervised application of language pedagogy. In an actual classroom, students will apply the theories, paradigms, and approaches to language learning they have studied. Practicum experience developed in consultation with the advisor, with approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
