    ('EALC-C 598', 'PEDAGOGY PROJECT', '3287', 'Class Status', NULL, NULL, 'Yuan Lu', 10, NULL, 'Research', '1–4', NULL, ARRAY[]::TEXT[], 'Demonstration of pedagogical understanding and sills. The project may take either of two forms: empirical study of pedagogical issues or significant materials development (e.g., set of course materials, course website, multimedia learning modules, testing instruments). Developed in consultation with the advisor, with approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
