    ('EALC-E 111', 'WAR AND VIOLENCE IN EAST ASIA', '29616', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 203', 'Morten Oxenboell', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores the history of physical violence in China, Japan, and Korea, with a special emphasis on state-sanctioned conflict. Examines the forms that war and violence took in the lives and minds of the residents of East Asia before the nineteenth century.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('EALC-E 115', 'ROMANCING EAST ASIA: LITERATURES OF LOVE FROM EARLY TIMES TO THE PRESENT', '29595', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 003', 'Hannah Airriess', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores diverse expressions of love--sexual, romantic, fantastic, erotic, brotherly, filial, nationalistic, etc., in different forms of literary works (myths, poetry, prose fiction). Examines how the concept of love was used by writers to explore questions of gender, class, and/or national identity.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 201', 'ISSUES IN EAST ASIAN LITERATURE', '15066', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FR C230', 'Xuan Ye', 0, NULL, 'Lecture', '3', 'FOREST QUAD', ARRAY[]::TEXT[], 'Survey and analysis of selected issues in East Asian literature and arts. Topics vary, but are generally on broad subjects that cut across fields, regions, and periods.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 204', 'ISSUES IN EAST ASIAN SOCIETY', '34927', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WI C111', 'Angela McClean', 0, NULL, 'Lecture', '3', 'WILLKIE C', ARRAY[]::TEXT[], 'Survey and analysis of selected issues pertinent to changes in East Asian political, economic, and cultural institutions of society. Topics vary, but are generally on broad subjects that cut across fields, regions, and periods.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('EALC-E 237', 'SAMURAI: CULTURE AND VIOLENCE IN PREMODERN JAPAN', '31491', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 1122', 'Morten Oxenboell', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An introduction to the history of the Japanese warriors (samurai) and how their culture shaped the use and perception of violence in society, politics, religion, and literature.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 300', 'STUDIES IN EAST ASIAN LITERATURE', '11853', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'AC C114', 'Nick Vogt', 1, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Selected issues and problems of importance to the understanding of East Asian literature, film or linguistics.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 305', 'KOREAN LANGUAGE AND CULTURE', '13943', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'TE F104', 'Hyo Lee', 20, NULL, 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'A survey of cultural, conceptual, and philosophical patterns, and the structure of Korean society, as reflected by the Korean language.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 306', 'PSYCHOLOGY OF CHINESE', '29619', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'TV 226', 'Chien-Jer Lin', 17, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on the cognitive mysteries that underlie key properties of the Chinese languages. Offers a roadmap for thinking about the cognitive as well as sociocultural issues related to the Chinese languages at different linguistic levels (speech, words, sentences, writing, classifiers, metaphor, etc.).', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('EALC-E 310', 'INTRODUCTION TO EAST ASIAN STUDIES', '5494', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'GA 0003', 'Scott O''Bryan', 27, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'A broad survey of Chinese, Japanese, and Korean civilizations that examines the idea of East Asia as a region with unifying social, cultural, and political characteristics, and its different societies, introducing analytic frameworks that have guided recent understandings of East Asia as a region and of individual East Asian societies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 311', 'KOREAN POPULAR CULTURE', '29624', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 005', 'Ria Chae', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Examines Korean popular culture through relevant technological innovations, sociopolitical changes, and historical forces. Engages with various forms of popular culture - popular music, television, film, digital/internet media, and food - to understand Korea as a dynamic site of cultural production and consumption.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 333', 'STUDIES IN CHINESE CINEMA', '12053', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1230', 'Tie Xiao', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Critical and historical perspectives on Chinese cinema from 1900 to the present, including cinema from Taiwan, Hong Kong and beyond. Topics include urban cinema, minority films, musicals, melodrama, adaptation, the silent era, filmmakers and movements.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 336', 'GHOSTS, IMMORTALS, ANIMAL SPIRITS: ENCOUNTERING THE SUPERNATURAL IN TRADITIONAL CHINESE CULTURE', '35275', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'ED 1204', 'Manling Luo', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Textual and visual representations of the supernatural in traditional Chinese culture spanning three millennia, from the earliest written records to the fiction of late imperial China. Offers a unique perspective into the ethics, literature, arts, and popular beliefs of traditional China. No prior knowledge of Chinese language is required.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 339', 'STUDIES IN SOUTH KOREAN CINEMA', '29620', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'RA B109', 'John Finch', 20, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Examines the intersection of gender, class, and nation in contemporary South Korea through the lens of cinema.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 342', 'MODERN KOREAN HISTORY', '33896', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 008', 'Ria Chae', 21, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Modern Korean history 1876-2010. Major themes: Korea''s inclusion in world system, intrusion of capitalism and transformation from agrarian to industrialized/consumer society. Course will explore modern systems (colonialism/neocolonialism, capitalism, social revolution/socialist economic experiments, Cold War, and globalization) through study of Korean history.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 350', 'STUDIES IN EAST ASIAN SOCIETY', '29622', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 130', 'Adam Liff', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Selected issues and problems of importance to the understanding of East Asian society.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
