    ('EALC-E 371', 'TWENTIETH CENTURY CHINESE LITERATURE', '11194', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 1220', 'Tie Xiao', 14, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('EALC-E 390', 'CONTEMPORARY CHINESE POLITICS', '35116', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 206', 'Jason Wu', 12, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analysis of trends and patterns in Chinese politics since 1949 with a focus on ideology and political culture, elites, party and government institutions, the policy making process, popular political participation, and the relationship between economic and political change. Political evolution of Taiwan is also considered.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
