    ('EALC-E 505', 'TOPICS IN EAST ASIAN STUDIES', '34976', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 008', 'Ria Chae', 21, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Graduate topics course that explores a variety of issues related to East Asian Languages and Culture.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 505', 'TOPICS IN EAST ASIAN STUDIES', '29634', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'AD A152', 'Angela McClean', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Graduate topics course that explores a variety of issues related to East Asian Languages and Culture.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 505', 'TOPICS IN EAST ASIAN STUDIES', '35286', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'ED 1204', 'Manling Luo', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Graduate topics course that explores a variety of issues related to East Asian Languages and Culture.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 525', 'KOREAN LANGUAGE AND CULTURE', '15164', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'TE F104', 'Hyo Lee', 3, NULL, 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'This course will critically examine the cultural and conceptual as well as philosophical makeup of Korean people, and the structure of Korean society, as reflected in the Korean language. Particularly focused on is how the patterns of manifestation of Korean cultures through Korean language are cross-cultural or culture-specific.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 533', 'STUDIES IN CHINESE CINEMA', '37192', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 1230', 'Tie Xiao', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Critical and historical perspectives on Chinese cinema, from the 1930''s to the 1990''s, including Taiwan and Hong Kong. Lectures and readings on the silent era, melodrama, musical, minority film, adaptation, the fifth generation, ideology, sexuality, urban cinema, and women''s cinema.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 595', 'INDIVIDUAL READINGS', '1434', 'Class Status', NULL, NULL, 'Nick Vogt', 9, NULL, 'Readings', '1–6', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intended for advanced students.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 595', 'INDIVIDUAL READINGS', '36728', 'Class Status', NULL, NULL, 'Hilary Holbrow', 5, NULL, 'Readings', '1–6', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intended for advanced students.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 595', 'INDIVIDUAL READINGS', '36928', 'Closed', NULL, 'GA 2021', 'Hannah Airriess', 0, NULL, 'Readings', '1–6', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intended for advanced students.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 596', 'READINGS IN PEDAGOGY', '3286', 'Class Status', NULL, NULL, 'Nick Vogt', 10, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Individualized readings in contemporary paradigms, critical issues, and techniques of teaching Asian languages.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 597', 'M.A. ESSAY', '3290', 'Class Status', NULL, NULL, 'Nick Vogt', 10, NULL, 'Research', '1–4', NULL, ARRAY[]::TEXT[], 'A capstone project recommended only for students pursuing a terminal M.A., the essay is intended to strengthen and demonstrate control over the variety of scholarly skills learned though graduate course work, rather than to demonstrate potential to undertake doctoral work. Developed in consultation with the graduate committee, with the approval of the Director of Graduate Studies.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 600', 'SEMINAR IN EAST ASIAN STUDIES', '29639', 'Class Status', 'Tu Tuesday 3:10 PM–5:40 PM', 'BH 214', 'Hilary Holbrow', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Studies in history, social sciences, and culture. Topics vary by semester, depending on student needs and interests.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 600', 'SEMINAR IN EAST ASIAN STUDIES', '29646', 'Class Status', 'W Wednesday 10:25 AM–1:25 PM', 'BH 123', 'Hannah Airriess', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Studies in history, social sciences, and culture. Topics vary by semester, depending on student needs and interests.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 604', 'EAST ASIAN STUDIES SCHOLARSHIP', '29626', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 134', 'Nick Vogt', 4, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced readings in East Asian studies scholarship, emphasizing seminal readings, key issues, and major theoretical perspectives.', ARRAY[]::TEXT[], NULL),
    ('EALC-E 700', 'M. A. THESIS', '1435', 'Class Status', NULL, NULL, 'Nick Vogt', 4, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EALC-G 599', 'THESIS RESEARCH', '3118', 'Class Status', NULL, NULL, 'Nick Vogt', 5, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('EALC-G 901', 'ADVANCED RESEARCH', '1436', 'Class Status', NULL, NULL, 'Nick Vogt', 8, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('EALC-H 399', 'READING FOR HONORS', '1437', 'Class Status', NULL, NULL, 'Tie Xiao', 10, NULL, 'Readings', '2–6', NULL, ARRAY[]::TEXT[], 'Designed to prepare the superior student for work on a specialized research project (H499). The choice of the number of credits as well as the nature of the texts to be used must be approved by the tutor.', ARRAY[]::TEXT[], NULL),
    ('EALC-H 499', 'HONORS THESIS', '1438', 'Class Status', NULL, NULL, 'Tie Xiao', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Designed to prepare the superior student for work on a specialized research project. The choice of the number of credits as well as the nature of the texts to be used must be approved by the tutor.', ARRAY[]::TEXT[], NULL),
